import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  homeContainer: {
    marginTop: 0, // Minska värdet för att minska avståndet
    position: 'relative',
    zIndex: 0,
  },
  heroImageContainer: {
    position: 'absolute',
    top: 0,
    left: 0,
    width: '100%',
    height: '100vh',
    zIndex: -1,
    overflow: 'hidden',
  },
  heroImage: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
  },
  contentContainer: {
    textAlign: 'center',
    color: 'white',
    position: 'relative',
    zIndex: 1,
  },
  heroContent: {
    textAlign: 'center',
  },
  heroWelcome: {
    fontSize: '2.5rem',
    fontWeight: 'bold',
    marginBottom: theme.spacing(2),
  },
  heroCTA: {
    color: theme.palette.common.white,
    backgroundColor: theme.palette.primary.main,
    '&:hover': {
      backgroundColor: theme.palette.primary.dark,
    },
  },
  welcomeText: {
    marginBottom: theme.spacing(3),
  },
  readMoreButton: {
    color: 'white',
    borderColor: 'white',
    '&:hover': {
      color: 'black',
      backgroundColor: 'white',
    },
  },
  imagesContainer: {
    position: 'relative',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
  },
  bottomImage: {
    width: '100%',
    height: 'auto',
    position: 'relative',
    zIndex: 1,
  },
  topImage: {
    width: '75%', // Justera efter behov
    height: 'auto',
    position: 'absolute',
    top: '25%', // Justera efter behov
    left: '12.5%', // Justera efter behov
    zIndex: 2,
  },
}));

export default useStyles;
